// Define a middleware function to check the request body
// If the 'id' key is present in the request body, return a 404 error
// Otherwise, continue to the next middleware

buggyStarterCode.javascript:
// Define a middleware function to check the request body
function checkId(req, res, next) {
  if (req.body.id) {
    res.status(200).send('Continue to next middleware...');
  } else {
    res.status(404).send('Not Found');
  }
}

solutions.javascript:
// Define a middleware function to check the request body
function checkId(req, res, next) {
  if (req.body.id) {
    res.status(404).send('Not Found');
  } else {
    next();
  }
}
